use std::{env, path};
use std::process::Command;

fn convert_file(filename: &str, desired_format: &str) -> Result<path::PathBuf, String> {
    let mut command = Command::new("");

    // Set the input file path
    command.arg(filename);

    // Set the output file path
    command.arg("-o").arg("output.ext");

    // Set the desired conversion format
    command.arg("-f").arg(desired_format);

    // Run the external conversion tool
    let output = command.output()?;

    // Check if the conversion was successful
    if !output.status.success() {
        return Err(String::from("Conversion failed"));
    }

    Ok(path::PathBuf::from("output.ext"))
}